import { ipcMain } from 'electron';
import {
  IPC_CHANNELS,
  MonitoringServerIdSchema,
  MonitoringUpdateConfigSchema,
  MonitoringGetLogsSchema,
  MonitoringTestNotificationSchema,
  MonitoringTestNotificationChannelSchema,
  MonitoringSendNotificationSchema,
  MonitoringAlertRuleSchema,
  MonitoringUpdateAlertRuleSchema,
  MonitoringDeleteAlertRuleSchema,
  MonitoringNotificationChannelSchema,
  MonitoringUpdateNotificationChannelSchema,
  MonitoringDeleteNotificationChannelSchema,
  MonitoringGetAlertsSchema,
  ApiResult,
  MonitoringConfig,
  AgentStatus,
  AgentLogs,
  AgentSourceCode,
  AlertRule,
  NotificationChannel,
  Alert,
  DependencyCheckResult,
} from './types';
import { monitoringAgentService } from '../services/MonitoringAgentService';

export function registerMonitoringHandlers() {
  void monitoringAgentService.migrateNotificationChannelSecrets().catch((error) => {
    console.warn('[Monitoring] Notification channel secrets migration failed:', error);
  });

  // ============ Agent Configuration ============

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_GET_CONFIG,
    async (_event, input): Promise<ApiResult<MonitoringConfig | null>> => {
      try {
        const { serverId } = MonitoringServerIdSchema.parse(input);
        const config = monitoringAgentService.getConfig(serverId);

        if (!config) {
          return { success: true, data: null };
        }

        return {
          success: true,
          data: {
            serverId: config.server_id,
            enabled: Boolean(config.enabled),
            intervalSeconds: config.interval_seconds,
            retentionDays: config.retention_days,
            agentInstalled: Boolean(config.agent_installed),
            agentVersion: config.agent_version,
            agentLastSeen: config.agent_last_seen,
            logMaxLines: config.log_max_lines,
            logMaxSizeMb: config.log_max_size_mb,
            logRetentionDays: config.log_retention_days,
          },
        };
      } catch (error) {
        console.error('Error getting monitoring config:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_UPDATE_CONFIG,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const config = MonitoringUpdateConfigSchema.parse(input);
        monitoringAgentService.upsertConfig(config.serverId, {
          enabled: config.enabled !== undefined ? (config.enabled ? 1 : 0) : undefined,
          interval_seconds: config.intervalSeconds,
          retention_days: config.retentionDays,
          log_max_lines: config.logMaxLines,
          log_max_size_mb: config.logMaxSizeMb,
          log_retention_days: config.logRetentionDays,
        });
        return { success: true };
      } catch (error) {
        console.error('Error updating monitoring config:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // ============ Agent Status & Installation ============

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_GET_AGENT_STATUS,
    async (_event, input): Promise<ApiResult<AgentStatus>> => {
      try {
        const { serverId } = MonitoringServerIdSchema.parse(input);
        const status = await monitoringAgentService.getAgentStatus(serverId);
        return { success: true, data: status };
      } catch (error) {
        console.error('Error getting agent status:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_INSTALL_AGENT,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { serverId } = MonitoringServerIdSchema.parse(input);
        await monitoringAgentService.installAgent(serverId);
        return { success: true };
      } catch (error) {
        console.error('Error installing monitoring agent:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_UNINSTALL_AGENT,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { serverId } = MonitoringServerIdSchema.parse(input);
        await monitoringAgentService.uninstallAgent(serverId);
        return { success: true };
      } catch (error) {
        console.error('Error uninstalling monitoring agent:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_PUSH_CONFIG,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { serverId } = MonitoringServerIdSchema.parse(input);
        const agentConfig = await monitoringAgentService.buildAgentConfig(serverId);
        await monitoringAgentService.pushConfig(serverId, agentConfig);
        return { success: true };
      } catch (error) {
        console.error('Error pushing monitoring config:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_GET_AGENT_LOGS,
    async (_event, input): Promise<ApiResult<AgentLogs>> => {
      try {
        const { serverId, lines } = MonitoringGetLogsSchema.parse(input);
        const logs = await monitoringAgentService.getAgentLogs(serverId, lines);
        return { success: true, data: logs };
      } catch (error) {
        console.error('Error getting agent logs:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_TRIGGER_RUN,
    async (_event, input): Promise<ApiResult<{ success: boolean; output: string }>> => {
      try {
        const { serverId } = MonitoringServerIdSchema.parse(input);
        const result = await monitoringAgentService.triggerManualRun(serverId);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error triggering manual agent run:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_TEST_NOTIFICATION,
    async (_event, input): Promise<ApiResult<{ success: boolean; output: string }>> => {
      try {
        const { serverId, channel } = MonitoringTestNotificationSchema.parse(input);
        const result = await monitoringAgentService.sendTestNotification(serverId, channel);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error testing notification:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_TEST_NOTIFICATION_CHANNEL,
    async (_event, input): Promise<ApiResult<{ success: boolean; output: string }>> => {
      try {
        const { serverId, channelId, title, message, severity } = MonitoringTestNotificationChannelSchema.parse(input);
        const result = await monitoringAgentService.sendChannelTestNotification(serverId, {
          channelId,
          title,
          message,
          severity,
        });
        return { success: true, data: result };
      } catch (error) {
        console.error('Error testing notification channel:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_SEND_NOTIFICATION,
    async (_event, input): Promise<ApiResult<{ success: boolean; output: string }>> => {
      try {
        const { serverId, severity, title, message, status } = MonitoringSendNotificationSchema.parse(input);
        const result = await monitoringAgentService.sendNotification(serverId, {
          severity,
          title,
          message,
          status,
        });
        return { success: true, data: result };
      } catch (error) {
        console.error('Error sending notification:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_GET_AGENT_SOURCE,
    async (): Promise<ApiResult<AgentSourceCode>> => {
      try {
        const source = monitoringAgentService.getAgentSourceCode();
        return { success: true, data: source };
      } catch (error) {
        console.error('Error getting agent source code:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_CHECK_DEPENDENCIES,
    async (_event, input): Promise<ApiResult<DependencyCheckResult>> => {
      try {
        const { serverId } = MonitoringServerIdSchema.parse(input);
        const result = await monitoringAgentService.checkDependencies(serverId);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error checking dependencies:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // ============ Alert Rules ============

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_GET_ALERT_RULES,
    async (_event, input): Promise<ApiResult<AlertRule[]>> => {
      try {
        const { serverId } = MonitoringServerIdSchema.parse(input);
        const rules = monitoringAgentService.getAlertRules(serverId);
        return { success: true, data: rules };
      } catch (error) {
        console.error('Error getting alert rules:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_CREATE_ALERT_RULE,
    async (_event, input): Promise<ApiResult<{ id: string }>> => {
      try {
        const rule = MonitoringAlertRuleSchema.parse(input);
        const id = monitoringAgentService.createAlertRule(rule);
        return { success: true, data: { id } };
      } catch (error) {
        console.error('Error creating alert rule:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_UPDATE_ALERT_RULE,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { id, ...updates } = MonitoringUpdateAlertRuleSchema.parse(input);
        monitoringAgentService.updateAlertRule(id, updates);
        return { success: true };
      } catch (error) {
        console.error('Error updating alert rule:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_DELETE_ALERT_RULE,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { id } = MonitoringDeleteAlertRuleSchema.parse(input);
        monitoringAgentService.deleteAlertRule(id);
        return { success: true };
      } catch (error) {
        console.error('Error deleting alert rule:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_INIT_DEFAULT_RULES,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { serverId } = MonitoringServerIdSchema.parse(input);
        monitoringAgentService.initializeDefaultRules(serverId);
        return { success: true };
      } catch (error) {
        console.error('Error initializing default rules:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // ============ Notification Channels ============

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_GET_NOTIFICATION_CHANNELS,
    async (_event, input): Promise<ApiResult<NotificationChannel[]>> => {
      try {
        const { serverId } = MonitoringServerIdSchema.parse(input);
        const channels = await monitoringAgentService.getNotificationChannels(serverId);
        return { success: true, data: channels };
      } catch (error) {
        console.error('Error getting notification channels:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_CREATE_NOTIFICATION_CHANNEL,
    async (_event, input): Promise<ApiResult<{ id: string }>> => {
      try {
        const channel = MonitoringNotificationChannelSchema.parse(input);
        const id = await monitoringAgentService.createNotificationChannel(channel);
        return { success: true, data: { id } };
      } catch (error) {
        console.error('Error creating notification channel:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_UPDATE_NOTIFICATION_CHANNEL,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { id, ...updates } = MonitoringUpdateNotificationChannelSchema.parse(input);
        await monitoringAgentService.updateNotificationChannel(id, updates);
        return { success: true };
      } catch (error) {
        console.error('Error updating notification channel:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_DELETE_NOTIFICATION_CHANNEL,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { id } = MonitoringDeleteNotificationChannelSchema.parse(input);
        monitoringAgentService.deleteNotificationChannel(id);
        return { success: true };
      } catch (error) {
        console.error('Error deleting notification channel:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // ============ Alerts History ============

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_GET_ALERTS,
    async (_event, input): Promise<ApiResult<Alert[]>> => {
      try {
        const { serverId, status, limit } = MonitoringGetAlertsSchema.parse(input);
        const alerts = monitoringAgentService.getAlerts(serverId, { status, limit });
        return { success: true, data: alerts };
      } catch (error) {
        console.error('Error getting alerts:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_GET_ACTIVE_ALERT_COUNT,
    async (_event, input): Promise<ApiResult<number>> => {
      try {
        const { serverId } = MonitoringServerIdSchema.parse(input);
        const count = monitoringAgentService.getActiveAlertCount(serverId);
        return { success: true, data: count };
      } catch (error) {
        console.error('Error getting active alert count:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MONITORING_SYNC_ALERTS,
    async (_event, input): Promise<ApiResult<{ synced: number; errors: string[] }>> => {
      try {
        const { serverId } = MonitoringServerIdSchema.parse(input);
        const result = await monitoringAgentService.syncAlertsFromVPS(serverId);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error syncing alerts from VPS:', error);
        return { success: false, error: String(error) };
      }
    }
  );
}
